function ModelDailyGameEnter:ParseModelConfig()
    self._PVEListData = {}
    self._PVPListData = {}
    ---@type V_DailyGameRef
    self._ExpandDevelopData = {}
    self._SubListData = {}
    local type
    for k, v in pairs(GameTable.DailyGamePlayRef) do
        type = v.type

        local list = {}
        if type == 1 then
            list = self._PVEListData
        elseif type == 2 then
            list = self._PVPListData
        elseif type == 3 then
            list = self._ExpandDevelopData
        end

        --如果是外围的
        if v.style == 2 then
            if not self._SubListData[v.group] then
                self._SubListData[v.group] = {}
            end
            local isCanInsert = true
            isCanInsert = gModelFunctionOpen:CheckIsShow(v.functionId)
            -- 【J绝色方块】日本DMM渠道——屏蔽绝色方块玩法入口（客户端
            if gLGameLanguage:IsJapanRegion() then
                local isDmm = gLSdkImpl:CallMethod(LSdkMethod.IsDMMPlatform)
                if isDmm then
                    if v.refId == 108 then
                        isCanInsert = false
                    end
                end
            end

            if isCanInsert then
                table.insert(self._SubListData[v.group], v)
            end
        else
            table.insert(list, v)
        end
    end

    for _, dataList in pairs(self._SubListData) do
        table.sort(dataList, function(a, b)
            return a.sort < b.sort
        end)
    end
    self:SortEnterList()
end

