function ModelDailyGameEnter:InitEnterClickFunc()
    self._EnterClickFunc = {
        [16400000] = function()
            --少女迷失
            local combatList = gModelFunctionOpen:GetFuncRelaCombat(16400000)
            for k, v in pairs(combatList) do
                if gLFightManager:IsCombatTypeInFight(k) then
                    gLFightManager:PrepareGoToBattle(k, {})
                    return
                end
            end
            if not gModelTower:GetIsUnlockRaceTower() then
                GF.OpenWndBottom("UITaWin")
            else
                GF.OpenWndBottom("UITaRacePopNew")
            end
        end,
        [ModelFunctionOpen.DREAMTRIP_ENTER] = function(itemdata, info, lockStr)
            --钻石秘境
            gModelGeneral:FastDreamTripEntrance()
        end,
        [18201001] = function(itemdata, info, lockStr)
            local funcList = gModelDailyGameEnter:GetItemInfoFunc(104)
            if funcList.isHaveData and funcList.isHaveData() then
                gModelFunctionOpen:Jump(18201001)
            else
                GF.ShowMessage(ccClientText(21075))
            end
        end
    }
end

