function ModelDailyGameEnter:ClickEnterItem(itemdata, info, lockStr)
    local functionId = itemdata.functionId

    local func = self._EnterClickFunc[itemdata.functionId]

    if func then
        func(itemdata, info, lockStr)
    else
        gModelFunctionOpen:Jump(functionId)
    end
end

