function ModelDailyGameEnter:GetExpandDevelopDatas()
    if not self._ExpandDevelopData then
        self:ParseModelConfig()
    end
    return self._ExpandDevelopData or {}
end

function ModelDailyGameEnter:CheckDailyGameRP(refId)
    local showRP = false
    local rpFunc = self:GetItemCheckSpecialRedpointFunc(refId)
    if rpFunc then
        showRP = rpFunc()
    else
        local ref = GameTable.DailyGamePlayRef[refId]
        if ref then
            local rpId = ref.redPoint
            if not rpId or rpId < 1 then
                rpId = ref.functionId
            end
            if rpId and rpId > 0 then
                showRP = gModelRedPoint:CheckShowRedPoint(rpId)
            end
        end
    end
    return showRP
end

